async function initializeAgentMcpServers(
  agentDefinition: AgentDefinition,
  parentClients: MCPServerConnection[],
): Promise<{
  clients: MCPServerConnection[]
  tools: Tools
  cleanup: () => Promise<void>
}> {
  // 如果Agent定义了专属MCP服务器，则初始化
  if (agentDefinition.mcpServers?.length) {
    const agentClients: MCPServerConnection[] = []
    const agentTools: Tool[] = []

    for (const spec of agentDefinition.mcpServers) {
      // 连接到MCP服务器并获取工具
      const client = await connectToServer(name, config)
      agentClients.push(client)

      if (client.type === 'connected') {
        const tools = await fetchToolsForClient(client)
        agentTools.push(...tools)
      }
    }

    return {
      clients: [...parentClients, ...agentClients],
      tools: agentTools,
      cleanup: async () => { /* 清理逻辑 */ }
    }
  }

  // 无专属服务器时直接返回父级配置
  return { clients: parentClients, tools: [], cleanup: async () => {} }
}

async function handleMessage(
  recipientName: string,
  content: string,
  summary: string | undefined,
  context: ToolUseContext,
): Promise<{ data: MessageOutput }> {
  const appState = context.getAppState()
  const teamName = getTeamName(appState.teamContext)
  const senderName = getAgentName() || (isTeammate() ? 'teammate' : TEAM_LEAD_NAME)

  // 写入收件箱
  await writeToMailbox(recipientName, {
    from: senderName,
    text: content,
    summary,
    timestamp: new Date().toISOString(),
    color: getTeammateColor(),
  }, teamName)

  return {
    data: {
      success: true,
      message: `Message sent to ${recipientName}'s inbox`,
      routing: { sender: senderName, target: `@${recipientName}` }
    }
  }
}

async function handleBroadcast(
  content: string,
  summary: string | undefined,
  context: ToolUseContext,
): Promise<{ data: BroadcastOutput }> {
  const appState = context.getAppState()
  const teamName = getTeamName(appState.teamContext)

  if (!teamName) {
    throw new Error('Not in a team context')
  }

  const teamFile = await readTeamFileAsync(teamName)
  const recipients: string[] = []

  // 收集除发送者外的所有团队成员
  for (const member of teamFile.members) {
    if (member.name.toLowerCase() !== senderName.toLowerCase()) {
      recipients.push(member.name)
    }
  }

  // 向每个成员发送消息
  for (const recipientName of recipients) {
    await writeToMailbox(recipientName, {
      from: senderName,
      text: content,
      summary,
      timestamp: new Date().toISOString(),
    }, teamName)
  }

  return {
    data: {
      success: true,
      message: `Message broadcast to ${recipients.length} teammate(s)`,
      recipients
    }
  }
}

